module top_module(
  input clk, reset,
  output reg [SIZE-1:0] out
);parameter SIZE = 4;

  reg [SIZE-1:0] counter_state;

  always @(posedge clk, posedge reset)
    begin
      if (reset) begin
        counter_state <= 0;
        out <= 0;
      end
      else begin
        counter_state <= {counter_state[SIZE-2:0], (counter_state[SIZE-1] ^ counter_state[SIZE-2])}; // Fixed the bit width issue here
        out <= counter_state;
      end
    end

endmodule
